server {
    listen 80;
    listen [::]:80;
    server_name api.datetris.date;

    client_max_body_size 20m;

    # ── /photos/<filename> direct-serve via nginx with auth_request gate ──
    # Filenames distinguish the two source dirs:
    #   photoface_*.jpg   → /var/lib/backa20/photos/   (face profile photo)
    #   gallery_*_full_length.jpg → /var/lib/backa20/media/ (body photo)
    # Other gallery slots (happy/funny/hobby/video) keep the old FastAPI
    # path with auth — they're not routed here.
    location ~ ^/photos/photoface_ {
        auth_request /api/auth/check;
        root /var/lib/backa20;
    }

    location ~ ^/photos/gallery_.+_full_length\.jpg$ {
        auth_request /api/auth/check;
        rewrite ^/photos/(.*)$ /media/$1 break;
        root /var/lib/backa20;
    }

    # Internal endpoint nginx subrequests for auth_request. `internal`
    # means external clients can't hit this URL — only nginx subrequests.
    location = /api/auth/check {
        internal;
        proxy_pass http://127.0.0.1:8000/api/auth/check;
        proxy_pass_request_body off;
        proxy_set_header Content-Length "";
    }

    location / {
        proxy_pass http://127.0.0.1:8000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";

        proxy_read_timeout 86400s;
    }
}

